          lockedAmount: 0,
        },
      });
    });

    this.logger.log(`任务付款完成: task=${taskId}, amount=${amount}, txNo=${transactionNo}`);
    return { message: '付款成功，任务已完成', transactionNo, amount, status: 'completed' };
  }
}

