function formatTime(ts: any) {
  if (!ts) return ''
  const d = new Date(ts)
  if (isNaN(d.getTime())) return ''
  const now = new Date()
  if (d.toDateString() === now.toDateString()) {
    return `${String(d.getHours()).padStart(2, '0')}:${String(d.getMinutes()).padStart(2, '0')}`
  }
  return `${d.getMonth() + 1}/${d.getDate()}`
}

// 后端统一返回 { list, total, page, pageSize } 或直接数组；历史消息 list 是倒序（createdAt desc）
function toArray(res: any): any[] {
  if (!res) return []
  if (Array.isArray(res)) return res
  if (Array.isArray(res.list)) return res.list
  if (Array.isArray(res.data?.list)) return res.data.list
  if (Array.isArray(res.data)) return res.data
  return []
}

export default function MessagePage() {
  const userStore = useUserStore()
  const [conversations, setConversations] = useState<any[]>([])
  const [activeConv, setActiveConv] = useState<any>(null)
  const [messages, setMessages] = useState<any[]>([])
  const [inputText, setInputText] = useState('')
  const [loadingList, setLoadingList] = useState(false)
  const [loadingMsg, setLoadingMsg] = useState(false)
  const [sending, setSending] = useState(false)
  const msgScrollId = useRef(`scroll-${Date.now()}`)
  const pollTimer = useRef<any>(null)

  // 加载会话列表（HTTP）
  const loadConversations = useCallback(async () => {
    setLoadingList(true)
    try {
      const res: any = await request({ url: '/conversations', method: 'GET', data: { page: 1, pageSize: 50 } })
      setConversations(toArray(res))
    } catch {
      // 静默失败，避免崩栈
    } finally {
      setLoadingList(false)
    }
  }, [])

  // 加载聊天记录（HTTP）
  const loadHistory = useCallback(async (convId: number) => {
    setLoadingMsg(true)
    try {
      const res: any = await request({
        url: `/conversations/${convId}/messages`,
        method: 'GET',
        data: { page: 1, pageSize: 50 },
      })
      // 后端按 createdAt desc 返回，前端倒回升序
      const list = toArray(res).slice().reverse()
      setMessages(list)
    } catch {
      setMessages([])
    } finally {
      setLoadingMsg(false)
    }
  }, [])

  // 聚焦会话时每 5 秒轮询一次新消息
  const startPoll = useCallback((convId: number) => {
    stopPoll()
    pollTimer.current = setInterval(async () => {
      try {
        const res: any = await request({
          url: `/conversations/${convId}/messages`,
          method: 'GET',
          data: { page: 1, pageSize: 50 },
        })
        const list = toArray(res).slice().reverse()
        setMessages(list)
      } catch {}
    }, 5000)
  }, [])

  function stopPoll() {
    if (pollTimer.current) {
      clearInterval(pollTimer.current)
      pollTimer.current = null
    }
  }

  useEffect(() => {
    loadConversations()
    return () => stopPoll()
  }, [loadConversations])

  // 每次小程序页面 onShow（例如从其他 tab 切回来）时刷新
  useDidShow(() => {
    if (activeConv) {
      loadHistory(activeConv.id)
    } else {
      loadConversations()
    }
  })

  const openConversation = useCallback(async (conv: any) => {
    setActiveConv(conv)
    setMessages([])
    await loadHistory(conv.id)
    startPoll(conv.id)
    // 进入会话→后端会自动标记已读，刷新角标
    unreadPoller.refresh()
  }, [loadHistory, startPoll])

  const closeConversation = useCallback(() => {
    stopPoll()
    setActiveConv(null)
    setMessages([])
    // 回列表时刷新一下最新的 lastMsgAt
    loadConversations()
    unreadPoller.refresh()
  }, [loadConversations])

  const sendMessage = useCallback(async () => {
    const text = inputText.trim()
    if (!text || !activeConv || sending) return

    const tempId = `t${Date.now()}`
    // 乐观 UI
    setMessages(prev => [...prev, {
      tempId,
      senderId: userStore.userId,
      senderType: 'worker',
      content: text,
      createdAt: new Date().toISOString(),
    }])
    setInputText('')
    setSending(true)

    try {
      const res: any = await request({
        url: `/conversations/${activeConv.id}/messages`,
        method: 'POST',
        data: { content: text, type: 'text' },
      })
      // 用服务端返回的正式消息替换乐观气泡
      if (res) {
        setMessages(prev => prev.map(m => m.tempId === tempId ? res : m))
      }
      // 视觉上我已读上去了，同步一下角标
      unreadPoller.refresh()
    } catch (err: any) {
      // 回滚
      setMessages(prev => prev.filter(m => m.tempId !== tempId))
      Taro.showToast({
        title: err?.message || '发送失败',
        icon: 'none',
      })
    } finally {
      setSending(false)
    }
  }, [inputText, activeConv, sending, userStore.userId])

  // ────────────── 会话列表视图 ──────────────
  if (!activeConv) {
    return (
      <View className='page'>
        <View className='top-bar'>
          <Text className='page-title'>消息</Text>
          <Text className='refresh-btn' onClick={loadConversations}>{loadingList ? '刷新中…' : '刷新'}</Text>
        </View>
        {conversations.length === 0 && !loadingList && (
          <View className='empty'>
            <Text className='empty-text'>暂无会话</Text>
          </View>
        )}
        {conversations.map(conv => (
          <View key={conv.id} className='conv-item' onClick={() => openConversation(conv)}>
            <View className='conv-avatar'>
              <Text className='avatar-text'>企</Text>
            </View>
            <View className='conv-info'>
              <Text className='conv-title'>任务#{conv.taskId}</Text>
              <Text className='conv-last-msg'>
                {conv.lastMessage?.content || '暂无消息'}
              </Text>
            </View>
            <View className='conv-right'>
              <Text className='conv-time'>{formatTime(conv.lastMessage?.createdAt || conv.lastMsgAt)}</Text>
              {conv.unreadCount > 0 && (
                <View className='unread-dot'>
                  <Text className='unread-num'>{conv.unreadCount > 99 ? '99+' : conv.unreadCount}</Text>
                </View>
              )}
            </View>
          </View>
        ))}
      </View>
    )
  }

  // ────────────── 聊天视图 ──────────────
  const myId = userStore.userId
  return (
    <View className='page chat-page'>
      <View className='chat-header'>
        <Text className='back-btn' onClick={closeConversation}>‹ 返回</Text>
        <Text className='chat-title'>任务#{activeConv.taskId}</Text>
      </View>
      <ScrollView
        className='msg-scroll'
        scrollY
        scrollIntoView={msgScrollId.current}
        scrollWithAnimation
      >
        {loadingMsg && messages.length === 0 && (
          <View className='loading-tip'><Text>加载中…</Text></View>
        )}
        {messages.map((msg, i) => {
          const isSelf = msg.senderType === 'worker'
            ? (msg.senderId === myId || msg.tempId)
            : false
          return (
            <View key={msg.id || msg._id || msg.tempId || i} className={`msg-row ${isSelf ? 'self' : 'other'}`}>
              <View className={`bubble ${isSelf ? 'bubble-self' : 'bubble-other'}`}>
                <Text className='bubble-text'>{msg.content}</Text>
              </View>
              <Text className='msg-time'>{formatTime(msg.createdAt)}</Text>
            </View>
          )
        })}
        <View id={msgScrollId.current} />
      </ScrollView>
      <View className='input-bar'>
        <Input
          className='msg-input'
          value={inputText}
          placeholder='说点什么...'
          onInput={(e: any) => setInputText(e.detail.value)}
          onConfirm={sendMessage}
          confirmType='send'
        />
        <View className={`send-btn ${(!inputText.trim() || sending) ? 'send-btn-disabled' : ''}`} onClick={sendMessage}>
          <Text className='send-text'>{sending ? '…' : '发送'}</Text>
        </View>
      </View>
    </View>
  )
}

/**
 * 未读消息轮询器
 *
 * 职责：
 * - 登录状态下每 30 秒调一次 GET /conversations，累加 unreadCount
 * - 给底部「消息」Tab（index=2）设置角标（showBadge / setTabBarBadge / removeTabBarBadge）
 * - 可被消息页在「打开会话/发送消息/返回列表」时主动调用 refresh() 同步
 * - App 切到后台自动停，切回前台自动恢复
 *
 * 使用：
 *   import { unreadPoller } from './utils/unread-poller'
 *   unreadPoller.start()   // 在 App onLaunch / useEffect 里调用一次
 *   unreadPoller.refresh() // 关键操作后手动同步
 *   unreadPoller.stop()    // 登出/后台时
 */
import Taro from '@tarojs/taro'
import { request } from '../api/request'

// 底部 Tab 中「消息」的索引（与 app.config.ts 中 tabBar.list 顺序一致）
const MESSAGE_TAB_INDEX = 2
const POLL_INTERVAL_MS = 30 * 1000

type State = {
  timer: any
  lastCount: number
  running: boolean
}

const state: State = {
  timer: null,
  lastCount: -1,
  running: false,
}

function isLoggedIn(): boolean {
  try {
    return !!Taro.getStorageSync('wc_token')
  } catch {
    return false
  }
}

async function fetchUnreadCount(): Promise<number> {
  const res: any = await request({
    url: '/conversations',
    method: 'GET',
    data: { page: 1, pageSize: 100 },
  })
  const list: any[] = Array.isArray(res) ? res
    : Array.isArray(res?.list) ? res.list
    : Array.isArray(res?.data?.list) ? res.data.list
    : []
  return list.reduce((sum, c) => sum + (Number(c.unreadCount) || 0), 0)
}

function applyBadge(count: number) {
  if (state.lastCount === count) return
  state.lastCount = count
  try {
    if (count > 0) {
      Taro.setTabBarBadge({
        index: MESSAGE_TAB_INDEX,
        text: count > 99 ? '99+' : String(count),
      }).catch(() => {})
    } else {
      Taro.removeTabBarBadge({ index: MESSAGE_TAB_INDEX }).catch(() => {})
    }
  } catch {
    // 非 TabBar 页面调用会 fail，忽略
  }
}

async function tick() {
  if (!isLoggedIn()) {
    applyBadge(0)
    return
  }
  try {
    const n = await fetchUnreadCount()
    applyBadge(n)
  } catch {
    // 静默失败；下次再试
  }
}

export const unreadPoller = {
  /** 启动轮询（幂等，重复调用只会保留一个 timer） */
  start() {
    if (state.running) return
    state.running = true
    // 启动时立即取一次
    tick()
    state.timer = setInterval(tick, POLL_INTERVAL_MS)
  },

  /** 停止轮询 */
  stop() {
    if (state.timer) {
      clearInterval(state.timer)
      state.timer = null
    }
    state.running = false
  },

  /** 手动触发一次（消息操作后立即同步） */
  refresh() {
    tick()
  },

  /** 登出时把角标清掉 */
  clear() {
    applyBadge(0)
  },
}

export default defineAppConfig({
  pages: [
    'pages/index/index',
    'pages/marketplace/index',
    'pages/message/index',
    'pages/my/index',
    'pages./home/recommend',
    'pages/profile/index',
    'pages/profile/card',
    'pages/profile/level',
  ],
  subPackages: [
    {
      root: 'subpackages/task',
      pages: [
        'pages/detail/index',
        'pages/execute/index',
        'pages/checkin/index',
        'pages/workhour/index',
        'pages/review/index',
        'pages/dispute/index',
        // V3.7
        'pages/checkpoint-submit/index',
        'pages/issue-report/index',
        'pages/comments/index',
      ],
    },
    {
      root: 'subpackages/marketplace',
      pages: ['pages/detail/index'],
    },
    {
      root: 'subpackages/wallet',
      pages: ['pages/index/index', 'pages/withdraw/index'],
    },
    {
      root: 'subpackages/auth',
      pages: ['pages/verify/index', 'pages/profile-edit/index'],
    },
    {
      root: 'subpackages/profile',
      pages: ['pages/portfolio/index', 'pages/settings/index', 'pages/applications/index'],
    },
  ],
  preloadRule: {
    'pages/index/index': {
      network: 'all',
      packages: ['subpackages/task'],
    },
    'pages/marketplace/index': {
      network: 'all',
      packages: ['subpackages/marketplace'],
    },
    'pages/my/index': {
      network: 'all',
      packages: ['subpackages/profile', 'subpackages/wallet', 'subpackages/auth'],
    },
  },
  tabBar: {
    color: '#999',
    selectedColor: '#0858F4',
    backgroundColor: '#fff',
    list: [
      { pagePath: 'pages/index/index', text: '首页' },
      { pagePath: 'pages/marketplace/index', text: '服务广场' },
      { pagePath: 'pages/message/index', text: '消息' },
      { pagePath: 'pages/my/index', text: '我的' },
    ],
  },
  window: {
    backgroundTextStyle: 'light',
    navigationBarBackgroundColor: '#0858F4',
    navigationBarTitleText: 'WeCreator',
    navigationBarTextStyle: 'white',
  },
})

import {
  Controller,
  Get,
  Put,
  Param,
  Query,
  ParseIntPipe,
  UseGuards,
  DefaultValuePipe,
} from '@nestjs/common';
import {
  ApiTags,
  ApiBearerAuth,
  ApiOperation,
  ApiQuery,
} from '@nestjs/swagger';
import { UserType } from '@prisma/client';
import { NotificationService } from './notification.service';
import { JwtAuthGuard } from '../auth/guards/jwt-auth.guard';
import { CurrentUser } from '../auth/decorators/current-user.decorator';

interface JwtPayload {
  userId: number;
  companyId?: number;
  userType: 'company' | 'worker';
}

@ApiTags('notification')
@ApiBearerAuth('access-token')
@UseGuards(JwtAuthGuard)
@Controller('notifications')
export class NotificationController {
  constructor(private readonly notificationService: NotificationService) {}

  /**
   * GET /api/v1/notifications
   * 通知列表（未读优先分页）
   */
  @Get()
  @ApiOperation({ summary: '通知列表（未读优先）' })
  @ApiQuery({ name: 'page',     required: false, type: Number })
  @ApiQuery({ name: 'pageSize', required: false, type: Number })
  async list(
    @CurrentUser() user: JwtPayload,
    @Query('page',     new DefaultValuePipe(1),  ParseIntPipe) page: number,
    @Query('pageSize', new DefaultValuePipe(20), ParseIntPipe) pageSize: number,
  ) {
    const userType = user.userType === 'company' ? UserType.company : UserType.worker;
    return this.notificationService.list(user.userId, userType, page, pageSize);
  }

  /**
   * GET /api/v1/notifications/unread-count
   * 未读计数（需在 :id 路由之前声明）
   */
  @Get('unread-count')
  @ApiOperation({ summary: '未读通知数' })
  async unreadCount(@CurrentUser() user: JwtPayload) {
    const userType = user.userType === 'company' ? UserType.company : UserType.worker;
    const count = await this.notificationService.getUnreadCount(user.userId, userType);
    return { count };
  }

  /**
   * PUT /api/v1/notifications/read-all
   * 全部已读
   */
  @Put('read-all')
  @ApiOperation({ summary: '全部已读' })
  async readAll(@CurrentUser() user: JwtPayload) {
    const userType = user.userType === 'company' ? UserType.company : UserType.worker;
    return this.notificationService.markAllRead(user.userId, userType);
  }

  /**
   * PUT /api/v1/notifications/:id/read
   * 单条已读
   */
  @Put(':id/read')
  @ApiOperation({ summary: '标记单条已读' })
  async readOne(
    @CurrentUser() user: JwtPayload,
    @Param('id', ParseIntPipe) id: number,
  ) {
    const userType = user.userType === 'company' ? UserType.company : UserType.worker;
    return this.notificationService.markOneRead(id, user.userId, userType);
  }
}

