import { useState, useEffect, useCallback, useRef } from 'react'
import { View, Text, Input, ScrollView } from '@tarojs/components'
import Taro, { useDidShow } from '@tarojs/taro'
import { request } from '../../api/request'
import { useUserStore } from '../../stores/user'
import { unreadPoller } from '../../utils/unread-poller'
import './index.scss'

function formatTime(ts: any) {
  if (!ts) return ''
  const d = new Date(ts)
  if (isNaN(d.getTime())) return ''
  const now = new Date()
  if (d.toDateString() === now.toDateString()) {
    return `${String(d.getHours()).padStart(2, '0')}:${String(d.getMinutes()).padStart(2, '0')}`
  }
  return `${d.getMonth() + 1}/${d.getDate()}`
}

function toArray(res: any): any[] {
  if (!res) return []
  if (Array.isArray(res)) return res
  if (Array.isArray(res.list)) return res.list
  if (Array.isArray(res.data?.list)) return res.data.list
  if (Array.isArray(res.data)) return res.data
  return []
}

// 通知类型图标 & 标签
const NOTIF_ICON: Record<string, string> = {
  task_invite: '📩', task_accepted: '✅', task_rejected: '❌',
  deliverable_submitted: '📦', review_result: '📋', settlement_completed: '💰',
  withdraw_completed: '🏦', system: '🔔',
}

export default function MessagePage() {
  const userStore = useUserStore()
  // 顶部 Tab: 'notifications' | 'chat'
  const [tab, setTab] = useState<'notifications' | 'chat'>('notifications')

  // ── 通知相关 ──
  const [notifications, setNotifications] = useState<any[]>([])
  const [notifLoading, setNotifLoading] = useState(false)
  const [notifUnread, setNotifUnread] = useState(0)

  const loadNotifications = useCallback(async () => {
    setNotifLoading(true)
    try {
      const res: any = await request({ url: '/notifications', method: 'GET', data: { page: 1, pageSize: 50 } })
      setNotifications(toArray(res))
      // 同步未读数
      const countRes: any = await request({ url: '/notifications/unread-count', method: 'GET' })
      setNotifUnread(countRes?.count ?? countRes?.data?.count ?? 0)
    } catch {
      // 静默
    } finally {
      setNotifLoading(false)
    }
  }, [])

  const markNotifRead = useCallback(async (id: number) => {
    try {
      await request({ url: `/notifications/${id}/read`, method: 'PUT' })
      setNotifications(prev => prev.map(n => n.id === id ? { ...n, isRead: true } : n))
      setNotifUnread(prev => Math.max(0, prev - 1))
    } catch {}
  }, [])

  const markAllNotifRead = useCallback(async () => {
    try {
      await request({ url: '/notifications/read-all', method: 'PUT' })
      setNotifications(prev => prev.map(n => ({ ...n, isRead: true })))
      setNotifUnread(0)
    } catch {}
  }, [])

  // 点击通知 → 跳转
  const handleNotifClick = useCallback((notif: any) => {
    if (!notif.isRead) markNotifRead(notif.id)
    // 根据类型跳转
    if (notif.type === 'task_invite' && notif.relatedTaskId) {
      // 零工端任务详情
      Taro.navigateTo({ url: `/subpackages/task/pages/detail/index?taskId=${notif.relatedTaskId}` })
    }
  }, [markNotifRead])

  // ── 聊天相关（保持原有逻辑）──
  const [conversations, setConversations] = useState<any[]>([])
  const [activeConv, setActiveConv] = useState<any>(null)
  const [messages, setMessages] = useState<any[]>([])
  const [inputText, setInputText] = useState('')
  const [loadingList, setLoadingList] = useState(false)
  const [loadingMsg, setLoadingMsg] = useState(false)
  const [sending, setSending] = useState(false)
  const msgScrollId = useRef(`scroll-${Date.now()}`)
  const pollTimer = useRef<any>(null)

  const loadConversations = useCallback(async () => {
    setLoadingList(true)
    try {
      const res: any = await request({ url: '/conversations', method: 'GET', data: { page: 1, pageSize: 50 } })
      setConversations(toArray(res))
    } catch {} finally { setLoadingList(false) }
  }, [])

  const loadHistory = useCallback(async (convId: number) => {
    setLoadingMsg(true)
    try {
      const res: any = await request({ url: `/conversations/${convId}/messages`, method: 'GET', data: { page: 1, pageSize: 50 } })
      setMessages(toArray(res).slice().reverse())
    } catch { setMessages([]) } finally { setLoadingMsg(false) }
  }, [])

  const startPoll = useCallback((convId: number) => {
    stopPoll()
    pollTimer.current = setInterval(async () => {
      try {
        const res: any = await request({ url: `/conversations/${convId}/messages`, method: 'GET', data: { page: 1, pageSize: 50 } })
        setMessages(toArray(res).slice().reverse())
      } catch {}
    }, 5000)
  }, [])

  function stopPoll() {
    if (pollTimer.current) { clearInterval(pollTimer.current); pollTimer.current = null }
  }

  useEffect(() => {
    loadNotifications()
    loadConversations()
    return () => stopPoll()
  }, [loadNotifications, loadConversations])

  useDidShow(() => {
    if (activeConv) {
      loadHistory(activeConv.id)
    } else {
      if (tab === 'notifications') loadNotifications()
      else loadConversations()
    }
  })

  const openConversation = useCallback(async (conv: any) => {
    setActiveConv(conv)
    setMessages([])
    await loadHistory(conv.id)
    startPoll(conv.id)
    unreadPoller.refresh()
  }, [loadHistory, startPoll])

  const closeConversation = useCallback(() => {
    stopPoll()
    setActiveConv(null)
    setMessages([])
    loadConversations()
    unreadPoller.refresh()
  }, [loadConversations])

  const sendMessage = useCallback(async () => {
    const text = inputText.trim()
    if (!text || !activeConv || sending) return
    const tempId = `t${Date.now()}`
    setMessages(prev => [...prev, { tempId, senderId: userStore.userId, senderType: 'worker', content: text, createdAt: new Date().toISOString() }])
    setInputText('')
    setSending(true)
    try {
      const res: any = await request({ url: `/conversations/${activeConv.id}/messages`, method: 'POST', data: { content: text, type: 'text' } })
      if (res) setMessages(prev => prev.map(m => m.tempId === tempId ? res : m))
      unreadPoller.refresh()
    } catch (err: any) {
      setMessages(prev => prev.filter(m => m.tempId !== tempId))
      Taro.showToast({ title: err?.message || '发送失败', icon: 'none' })
    } finally { setSending(false) }
  }, [inputText, activeConv, sending, userStore.userId])

  // ══════════════ 聊天详情视图 ══════════════
  if (activeConv) {
    const myId = userStore.userId
    return (
      <View className='page chat-page'>
        <View className='chat-header'>
          <Text className='back-btn' onClick={closeConversation}>‹ 返回</Text>
          <Text className='chat-title'>任务#{activeConv.taskId}</Text>
        </View>
        <ScrollView className='msg-scroll' scrollY scrollIntoView={msgScrollId.current} scrollWithAnimation>
          {loadingMsg && messages.length === 0 && <View className='loading-tip'><Text>加载中…</Text></View>}
          {messages.map((msg, i) => {
            const isSelf = msg.senderType === 'worker' ? (msg.senderId === myId || msg.tempId) : false
            return (
              <View key={msg.id || msg._id || msg.tempId || i} className={`msg-row ${isSelf ? 'self' : 'other'}`}>
                <View className={`bubble ${isSelf ? 'bubble-self' : 'bubble-other'}`}>
                  <Text className='bubble-text'>{msg.content}</Text>
                </View>
                <Text className='msg-time'>{formatTime(msg.createdAt)}</Text>
              </View>
            )
          })}
          <View id={msgScrollId.current} />
        </ScrollView>
        <View className='input-bar'>
          <Input className='msg-input' value={inputText} placeholder='说点什么...' onInput={(e: any) => setInputText(e.detail.value)} onConfirm={sendMessage} confirmType='send' />
          <View className={`send-btn ${(!inputText.trim() || sending) ? 'send-btn-disabled' : ''}`} onClick={sendMessage}>
            <Text className='send-text'>{sending ? '…' : '发送'}</Text>
          </View>
        </View>
      </View>
    )
  }

  // ══════════════ 列表视图（通知 / 聊天 Tab）══════════════
  return (
    <View className='page'>
      {/* 顶部 Tab 切换 */}
      <View className='msg-tabs'>
        <View
          className={`msg-tab ${tab === 'notifications' ? 'msg-tab-active' : ''}`}
          onClick={() => { setTab('notifications'); loadNotifications() }}
        >
          <Text className='msg-tab-text'>通知</Text>
          {notifUnread > 0 && <View className='tab-badge'><Text className='tab-badge-text'>{notifUnread > 99 ? '99+' : notifUnread}</Text></View>}
        </View>
        <View
          className={`msg-tab ${tab === 'chat' ? 'msg-tab-active' : ''}`}
          onClick={() => { setTab('chat'); loadConversations() }}
        >
          <Text className='msg-tab-text'>聊天</Text>
        </View>
      </View>

      {/* ── 通知列表 ── */}
      {tab === 'notifications' && (
        <View className='notif-list'>
          {notifUnread > 0 && (
            <View className='notif-read-all' onClick={markAllNotifRead}>
              <Text className='notif-read-all-text'>全部已读</Text>
            </View>
          )}
          {notifications.length === 0 && !notifLoading && (
            <View className='empty'><Text className='empty-text'>暂无通知</Text></View>
          )}
          {notifLoading && notifications.length === 0 && (
            <View className='empty'><Text className='empty-text'>加载中…</Text></View>
          )}
          {notifications.map(notif => (
            <View
              key={notif.id}
              className={`notif-item ${notif.isRead ? 'notif-read' : 'notif-unread'}`}
              onClick={() => handleNotifClick(notif)}
            >
              <View className='notif-icon'>
                <Text>{NOTIF_ICON[notif.type] || '🔔'}</Text>
              </View>
              <View className='notif-body'>
                <Text className='notif-title'>{notif.title}</Text>
                <Text className='notif-content'>{notif.content}</Text>
                <Text className='notif-time'>{formatTime(notif.createdAt)}</Text>
              </View>
              {!notif.isRead && <View className='notif-dot' />}
            </View>
          ))}
        </View>
      )}

      {/* ── 聊天列表 ── */}
      {tab === 'chat' && (
        <View className='conv-list'>
          <View className='top-bar'>
            <Text className='refresh-btn' onClick={loadConversations}>{loadingList ? '刷新中…' : '刷新'}</Text>
          </View>
          {conversations.length === 0 && !loadingList && (
            <View className='empty'><Text className='empty-text'>暂无会话</Text></View>
          )}
          {conversations.map(conv => (
            <View key={conv.id} className='conv-item' onClick={() => openConversation(conv)}>
              <View className='conv-avatar'><Text className='avatar-text'>企</Text></View>
              <View className='conv-info'>
                <Text className='conv-title'>任务#{conv.taskId}</Text>
                <Text className='conv-last-msg'>{conv.lastMessage?.content || '暂无消息'}</Text>
              </View>
              <View className='conv-right'>
                <Text className='conv-time'>{formatTime(conv.lastMessage?.createdAt || conv.lastMsgAt)}</Text>
                {conv.unreadCount > 0 && (
                  <View className='unread-dot'><Text className='unread-num'>{conv.unreadCount > 99 ? '99+' : conv.unreadCount}</Text></View>
                )}
              </View>
            </View>
          ))}
        </View>
      )}
    </View>
  )
}

