  &:active { opacity: 1; transform: none; }
}

.send-text {
  font-size: $font-base;
  color: $color-text-white;
  font-weight: $weight-semibold;
}

// ═══════════════════════════════════════════════════════════
// WeCreator Design System v1.1
// 小程序全局设计 Token — 所有页面必须引用此文件
// 对齐 PC 端 Design System V1.1（品牌色 #0858F4 → tokens #2B5BFC）
// ═══════════════════════════════════════════════════════════

// ── 品牌色 ──────────────────────────────────────────────
$color-primary:       #0858F4;   // V1.1 品牌主色（画板 1496 提取）
$color-primary-light: #D0DCFC;   // V1.1 浅蓝强调区
$color-primary-dark:  #0040C0;   // V1.1 深蓝悬停
$color-primary-bg:    rgba(8, 88, 244, 0.08);
$color-accent:        #FC6400;   // V1.1 CTA 强调橙

// ── 功能色 ──────────────────────────────────────────────
$color-success:       #38D048;   // V1.1 成功绿
$color-success-bg:    #E8F8E8;
$color-warning:       #F5A623;   // V1.1 警告橙
$color-warning-bg:    #FFF8E8;
$color-danger:        #E8383C;   // V1.1 错误红
$color-danger-bg:     #FFF1F0;
$color-info:          #3B82F6;
$color-info-bg:       #DBEAFE;
$color-price:         #E8383C;
$color-gold:          #F5A623;
$color-teal:          #34B8A8;   // V1.1 补充色
$color-purple:        #E04CFC;   // V1.1 补充色

// ── 文字色 ──────────────────────────────────────────────
$color-text-primary:     #181818;  // V1.1 标题
$color-text-regular:     #333333;  // 正文
