}
// 绿色气泡和白色气泡文字都用深色
.wc-text-dark { color: #181818; }

/* ── 底部输入栏 ── */
.wc-input-bar {
  display: flex; align-items: center;
  padding: 14rpx 20rpx;
  background: #F6F6F6;
  border-top: 1rpx solid #E0E0E0;
  @include safe-bottom(14rpx);
  gap: 16rpx;
}

.wc-input-wrap {
  flex: 1;
  background: #FFFFFF;
  border-radius: 8rpx;
  border: 1rpx solid #E0E0E0;
  padding: 0;
}

.wc-input {
  width: 100%;
  height: 72rpx;
  padding: 0 20rpx;
