import {
  Controller,
  Get,
  Put,
  Param,
  Query,
  ParseIntPipe,
  UseGuards,
  DefaultValuePipe,
} from '@nestjs/common';
import {
  ApiTags,
  ApiBearerAuth,
  ApiOperation,
  ApiQuery,
} from '@nestjs/swagger';
import { UserType } from '@prisma/client';
import { NotificationService } from './notification.service';
import { JwtAuthGuard } from '../auth/guards/jwt-auth.guard';
import { CurrentUser } from '../auth/decorators/current-user.decorator';

interface JwtPayload {
  userId: number;
  companyId?: number;
  userType: 'company' | 'worker';
}

@ApiTags('notification')
@ApiBearerAuth('access-token')
@UseGuards(JwtAuthGuard)
@Controller('notifications')
export class NotificationController {
  constructor(private readonly notificationService: NotificationService) {}

  /**
   * GET /api/v1/notifications
   * 通知列表（未读优先分页）
   */
  @Get()
  @ApiOperation({ summary: '通知列表（未读优先）' })
  @ApiQuery({ name: 'page',     required: false, type: Number })
  @ApiQuery({ name: 'pageSize', required: false, type: Number })
  async list(
    @CurrentUser() user: JwtPayload,
    @Query('page',     new DefaultValuePipe(1),  ParseIntPipe) page: number,
    @Query('pageSize', new DefaultValuePipe(20), ParseIntPipe) pageSize: number,
  ) {
    const userType = user.userType === 'company' ? UserType.company : UserType.worker;
    return this.notificationService.list(user.userId, userType, page, pageSize);
  }

  /**
   * GET /api/v1/notifications/unread-count
   * 未读计数（需在 :id 路由之前声明）
   */
  @Get('unread-count')
  @ApiOperation({ summary: '未读通知数' })
  async unreadCount(@CurrentUser() user: JwtPayload) {
    const userType = user.userType === 'company' ? UserType.company : UserType.worker;
    const count = await this.notificationService.getUnreadCount(user.userId, userType);
    return { count };
  }

  /**
   * PUT /api/v1/notifications/read-all
   * 全部已读
   */
  @Put('read-all')
  @ApiOperation({ summary: '全部已读' })
  async readAll(@CurrentUser() user: JwtPayload) {
    const userType = user.userType === 'company' ? UserType.company : UserType.worker;
    return this.notificationService.markAllRead(user.userId, userType);
  }

  /**
   * PUT /api/v1/notifications/:id/read
   * 单条已读
   */
  @Put(':id/read')
  @ApiOperation({ summary: '标记单条已读' })
  async readOne(
    @CurrentUser() user: JwtPayload,
    @Param('id', ParseIntPipe) id: number,
  ) {
    const userType = user.userType === 'company' ? UserType.company : UserType.worker;
    return this.notificationService.markOneRead(id, user.userId, userType);
  }
}

/**
 * NotificationService — 通知中心
 *
 * Schema V2 字段变更:
 *  - userId    → recipientId
 *  - userType  → recipientType
 *  - relatedId → relatedTaskId
 */
import { Injectable } from '@nestjs/common';
import { PrismaService } from '../../prisma';
import { NotificationType, UserType } from '@prisma/client';
import { MessageGateway } from '../message/message.gateway';

export interface CreateNotificationDto {
  recipientId:   bigint;
  recipientType: UserType;
  type:          NotificationType;
  title:         string;
  content:       string;
  relatedTaskId?: bigint;
  templateCode?: string;
}

@Injectable()
export class NotificationService {
  constructor(
    private readonly prisma: PrismaService,
    private readonly messageGateway: MessageGateway,
  ) {}

  // ──────────────────────────────────────────
  // 创建通知（内部调用，由业务事件触发）
  // ──────────────────────────────────────────
  async create(dto: CreateNotificationDto) {
    const notification = await this.prisma.notification.create({
      data: {
        recipientId:   dto.recipientId,
        recipientType: dto.recipientType,
        type:          dto.type,
        title:         dto.title,
        content:       dto.content,
        relatedTaskId: dto.relatedTaskId ?? null,
        templateCode:  dto.templateCode ?? null,
      },
    });

    // 通过 WebSocket 实时推送未读数变化
    const unreadCount = await this.getUnreadCount(
      Number(dto.recipientId),
      dto.recipientType,
    );
    this.messageGateway.sendToUser(
      Number(dto.recipientId),
      'notification_count',
      { unreadCount },
    );

    return notification;
  }

  // ──────────────────────────────────────────
  // 通知列表（分页，未读优先）
  // GET /notifications
  // ──────────────────────────────────────────
  async list(
    userId: number,
    userType: UserType,
    page = 1,
    pageSize = 20,
  ) {
    const skip = (page - 1) * pageSize;
    const where = { recipientId: BigInt(userId), recipientType: userType };

    const [total, list] = await Promise.all([
      this.prisma.notification.count({ where }),
      this.prisma.notification.findMany({
        where,
        orderBy: [{ isRead: 'asc' }, { createdAt: 'desc' }],
        skip,
        take: pageSize,
      }),
    ]);

    return {
      list: list.map((n) => ({
        ...n,
        id: Number(n.id),
        recipientId: Number(n.recipientId),
        relatedTaskId: n.relatedTaskId ? Number(n.relatedTaskId) : null,
      })),
      total,
      page,
      pageSize,
    };
  }

  // ──────────────────────────────────────────
  // 标记单条已读
  // PUT /notifications/:id/read
  // ──────────────────────────────────────────
  async markOneRead(id: number, userId: number, userType: UserType) {
    await this.prisma.notification.updateMany({
      where: { id: BigInt(id), recipientId: BigInt(userId), recipientType: userType },
      data: { isRead: true },
    });
    return { success: true };
  }

  // ──────────────────────────────────────────
  // 全部已读
  // PUT /notifications/read-all
  // ──────────────────────────────────────────
  async markAllRead(userId: number, userType: UserType) {
    const { count } = await this.prisma.notification.updateMany({
      where: {
        recipientId: BigInt(userId),
        recipientType: userType,
        isRead: false,
      },
      data: { isRead: true },
    });
    return { updated: count };
  }

  // ──────────────────────────────────────────
  // 未读计数
  // GET /notifications/unread-count
  // ──────────────────────────────────────────
  async getUnreadCount(userId: number, userType: UserType): Promise<number> {
    return this.prisma.notification.count({
      where: {
        recipientId: BigInt(userId),
        recipientType: userType,
        isRead: false,
      },
    });
  }
}

/**
 * 零工端任务 API
 */
import { request } from './request'

export interface WorkerTask {
  assignmentId: number
  status: 'invited' | 'accepted' | 'rejected' | 'completed' | 'expired' | 'withdrawn'
  progress: number
  slotIndex: number
  invitedAt: string
  acceptedAt: string | null
  task: {
    taskId: number
    title: string
    taskMode: string
    status: string
  }
  role: {
    roleName: string
    budget: number
  }
  /** V3.7: 未解决问题数（任务卡片 ⚠️ 展示） */
  unresolvedIssueCount?: number
}

export interface UpdateProgressPayload {
  progress: number
  note?: string
  /** V3.7 日报：今日摘要、5–0-500 字 */
  dailySummary?: string
  /** V3.7 日报：明日计划 */
  tomorrowPlan?: string
  /** V3.7 日报：遇到的问题 */
  issues?: string
}

export const taskApi = {
  /** 我的任务列表 */
  list: (status?: string) =>
    request<WorkerTask[]>({
      url: '/worker/tasks',
      data: status ? { status } : undefined,
    }),

  /** 接受邀约 */
  accept: (assignmentId: number) =>
    request<{ message: string }>({
      url: `/worker/tasks/${assignmentId}/accept`,
      method: 'POST',
    }),

  /** 婉拒邀约 */
  reject: (assignmentId: number) =>
    request<{ message: string }>({
      url: `/worker/tasks/${assignmentId}/reject`,
      method: 'POST',
    }),

  /** 更新进度 + V3.7 结构化日报 */
  updateProgress: (assignmentId: number, payload: UpdateProgressPayload) =>
    request<{ message: string; progressUpdateId?: number }>({
      url: `/worker/tasks/${assignmentId}/progress`,
      method: 'POST',
      data: payload,
    }),

  /** 提交交付物 */
  submitDeliverable: (assignmentId: number, data: {
    title: string; fileUrl: string; fileType?: string; note?: string
  }) =>
    request<{ message: string }>({
      url: `/worker/tasks/${assignmentId}/deliverables`,
      method: 'POST',
      data,
    }),

  /** V3.9: 发起验收申请 */
  requestAcceptance: (assignmentId: number) =>
    request<{ message: string; status: string }>({
      url: `/worker/tasks/${assignmentId}/request-acceptance`,
      method: 'POST',
    }),
}

