edits.newText:
.notif-red-dot {
  width: 16rpx; height: 16rpx;
  border-radius: 8rpx;
  background: #ff4d4f;
  position: absolute;
  top: $space-md; right: $page-padding;
}

/* ── 通知卡片容器 ── */
.notif-card {
  background: #fff;
  @include divider($color-border-light);
}

/* 展开箭头 */
.notif-expand-icon {
  @include flex-center;
  width: 40rpx; flex-shrink: 0;
}
.expand-arrow {
  font-size: 32rpx; color: $color-text-disabled;
  transform: rotate(90deg);
  transition: transform 0.2s ease;
  display: inline-block;
}
.expand-arrow-up {
  transform: rotate(-90deg);
}

/* ── 任务简要信息卡片 ── */
.notif-task-card {
  margin: 0 $page-padding 20rpx;
  padding: 24rpx;
  background: #F7F8FA;
  border-radius: $radius-md;
  border-left: 6rpx solid $color-primary;
  &:active { background: #EBEDF0; }
}

.task-card-header {
  display: flex; align-items: center;
  justify-content: space-between;
  margin-bottom: 20rpx;
}
.task-card-title {
  font-size: $font-md; font-weight: $weight-semibold;
  color: $color-text-primary;
  flex: 1;
  @include text-ellipsis;
}
.task-card-status {
  padding: 4rpx 16rpx;
  border-radius: $radius-xl;
  background: $color-primary-bg;
  flex-shrink: 0; margin-left: 12rpx;
}
.task-card-status-text {
  font-size: $font-xs; color: $color-primary;
  font-weight: $weight-medium;
}

.task-card-info {
  display: flex; flex-direction: column;
  gap: 16rpx;
}

.task-info-row {
  display: flex; align-items: center;
  gap: 10rpx;
}
.task-info-icon { font-size: 24rpx; flex-shrink: 0; }
.task-info-label {
  font-size: $font-sm; color: $color-text-secondary;
  width: 120rpx; flex-shrink: 0;
}
.task-info-value {
  font-size: $font-sm; color: $color-text-primary;
  font-weight: $weight-medium;
  flex: 1;
}
.task-info-price {
  color: $color-price;
  font-weight: $weight-bold;
  font-size: $font-base;
}

.task-card-footer {
  margin-top: 20rpx; padding-top: 16rpx;
  border-top: 1rpx solid $color-border-light;
  display: flex; justify-content: flex-end;
}
.task-card-link {
  font-size: $font-sm; color: $color-primary;
  font-weight: $weight-medium;
  &:active { opacity: 0.7; }
}

